class Solution:
    def removeAlmostEqualCharacters(self, word: str) -> int:
        n = len(word)
        if n == 0:
            return 0
        INF = float('inf')
        dp = [0 if chr(97 + c) == word[0] else 1 for c in range(26)]
        for i in range(1, n):
            orig = word[i]
            new_dp = [INF] * 26
            for c in range(26):
                ch = chr(97 + c)
                own_cost = 0 if ch == orig else 1
                best = INF
                for p in range(26):
                    if abs(p - c) <= 1:
                        continue
                    if dp[p] < best:
                        best = dp[p]
                new_dp[c] = best + own_cost
            dp = new_dp
        return min(dp)

