class Solution:
    def removeAlmostEqualCharacters(self, word: str) -> int:
        n = len(word)
        count = 0
        i = 1
        while i < n:
            if abs(ord(word[i]) - ord(word[i - 1])) <= 1:
                count += 1
                i += 2
            else:
                i += 1
        return count

