var removeAlmostEqualCharacters = function(word) {
    const n = word.length;
    let count = 0;
    let i = 1;
    while (i < n) {
        if (Math.abs(word.charCodeAt(i) - word.charCodeAt(i - 1)) <= 1) {
            count++;
            i += 2;
        } else {
            i++;
        }
    }
    return count;
};
